import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import './App.css';

// --- 1. КОМПОНЕНТ АВТОРИЗАЦИИ (Вход + Регистрация) ---
const AuthScreen = ({ onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [pass, setPass] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = () => {
    if (isLogin) {
      onLogin(email, pass);
    } else {
      onRegister(name, email, pass);
    }
  };

  return (
    <div className="login-page">
      <div className="login-card fade-in">
        <h2>{isLogin ? 'С возвращением!' : 'Стать гостем'}</h2>
        {!isLogin && (
          <input type="text" placeholder="Ваше имя" onChange={e => setName(e.target.value)} />
        )}
        <input type="email" placeholder="Email" onChange={e => setEmail(e.target.value)} />
        <input type="password" placeholder="Пароль" onChange={e => setPass(e.target.value)} />
        <button className="btn-main" onClick={handleSubmit}>
          {isLogin ? 'Войти' : 'Создать аккаунт'}
        </button>
        <p className="toggle-auth" onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Нет аккаунта? Создать' : 'Уже есть аккаунт? Войти'}
        </p>
      </div>
    </div>
  );
};

// --- 2. КОМПОНЕНТ МЕНЮ ---
const Menu = ({ onOrder }) => {
  const items = [
    { id: 1, name: 'Эспрессо', price: 150, img: '☕' },
    { id: 2, name: 'Капучино', price: 250, img: '🥛' },
    { id: 3, name: 'Круассан', price: 210, img: '🥐' }
  ];
  return (
    <div className="page">
      <h2>Меню</h2>
      <div className="product-grid">
        {items.map(item => (
          <div key={item.id} className="product-card" onClick={() => onOrder(item)}>
            <span style={{fontSize: '40px'}}>{item.img}</span>
            <h3>{item.name}</h3>
            <p>{item.price} ₽</p>
          </div>
        ))}
      </div>
    </div>
  );
};

// --- 3. КОМПОНЕНТ ПРОФИЛЯ ---
const Profile = ({ user, orders, onLogout }) => (
  <div className="page">
    <div className="user-info-card">
      <h3>Привет, {user?.company_name || 'Гость'}!</h3>
      <button onClick={onLogout} className="btn-logout">Выйти</button>
    </div>
    <h3>История заказов</h3>
    <div className="order-history">
      {orders.map(o => (
        <div key={o.id} className={`order-item ${o.status === 'Готов' ? 'ready' : ''}`}>
          <span>#{o.id} — {o.description}</span>
          <span className="status-label">{o.status}</span>
        </div>
      ))}
    </div>
  </div>
);

// --- 4. ОСНОВНОЙ КОМПОНЕНТ APP ---
export default function App() {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')));
  const [orders, setOrders] = useState([]);

  // Функция входа
  const login = async (email, password) => {
    const res = await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ action: 'login', email, password })
    });
    const data = await res.json();
    if (data.id) {
      setUser(data);
      localStorage.setItem('user', JSON.stringify(data));
    } else {
      alert(data.error || "Ошибка входа");
    }
  };

  // Функция регистрации
  const register = async (name, email, password) => {
    const res = await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ action: 'register', name, email, password })
    });
    const data = await res.json();
    if (data.id) {
      setUser(data);
      localStorage.setItem('user', JSON.stringify(data));
    } else {
      alert(data.error || "Ошибка регистрации");
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  const handleOrder = async (item) => {
    if (!user) return;
    await fetch('http://localhost:8000/index.php', {
      method: 'POST',
      body: JSON.stringify({ user_id: user.id, description: item.name, total_amount: item.price })
    });
    alert('Заказ отправлен!');
  };

  // Хук useEffect должен быть в теле функции ДО всех return
  useEffect(() => {
    if (!user) return; // Условие внутри хука, а не вокруг него

    const fetchOrders = () => {
      fetch(`http://localhost:8000/index.php?user_id=${user.id}`)
        .then(res => res.json())
        .then(data => setOrders(Array.isArray(data) ? data : []))
        .catch(err => console.error("Ошибка загрузки:", err));
    };

    fetchOrders();
    const interval = setInterval(fetchOrders, 3000);
    return () => clearInterval(interval);
  }, [user]);

  // Только после всех хуков делаем проверку на авторизацию
  if (!user) {
    return <AuthScreen onLogin={login} onRegister={register} />;
  }

  return (
    <Router>
      <div className="paradise-app">
        <Routes>
          <Route path="/" element={<Menu onOrder={handleOrder} />} />
          <Route path="/profile" element={<Profile user={user} orders={orders} onLogout={logout} />} />
        </Routes>

        <nav className="bottom-nav">
          <Link to="/" className="nav-item">🍴 Меню</Link>
          <Link to="/profile" className="nav-item">👤 Профиль</Link>
        </nav>
      </div>
    </Router>
  );
}
